function solve(prices: number[], strategy: number[], k: number): number {
    let maxProfit = 0;
    const n = prices.length;

    // Calculate the original profit
    let profit = 0;
    for (let i = 0; i < n; i++) {
        profit += strategy[i] * prices[i];
    }
    maxProfit = profit;

    // Try to modify each possible subarray of length k
    for (let i = 0; i <= n - k; i++) {
        // Calculate the profit change if we modify the subarray [i, i + k - 1]
        let change = 0;
        // Original strategy in the subarray: first k/2 elements are -1, next k/2 are 1
        for (let j = 0; j < k; j++) {
            if (j < k / 2) {
                // Original is -1, now it's 0 (hold)
                change += (-1 * prices[i + j]) - (0 * prices[i + j]);
            } else {
                // Original is 1, now it's 1 (sell)
                // No change
            }
        }
        // Calculate the profit change for the rest of the array
        for (let j = 0; j < n; j++) {
            if (j < i || j >= i + k) {
                // Original strategy is unchanged
                // No change
            }
        }
        // Update maxProfit
        maxProfit = Math.max(maxProfit, profit + change);
    }

    return maxProfit;
}

